import{_ as e}from"./chunks/quickstart_01.CAs9iatn.js";import{_ as a,o as r,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Быстрый старт","description":"","frontmatter":{},"headers":[],"relativePath":"ru/getting-started/quickstart.md","filePath":"ru/getting-started/quickstart.md"}'),o={name:"ru/getting-started/quickstart.md"};function l(c,t,n,d,p,g){return r(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="быстрыи-старт" tabindex="-1"><i class="ph ph-target"></i> Быстрый старт <a class="header-anchor" href="#быстрыи-старт" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-target&quot;&gt;&lt;/i&gt; Быстрый старт&quot;">​</a></h1><p>Плагин WebAP спроектирован по принципу <em>Plug-and-Play</em>. Вам не нужно писать код или добавлять менеджеры на стартовые сцены — система инициализируется автоматически.</p><h2 id="_1-включение-плагина" tabindex="-1">1. Включение плагина <a class="header-anchor" href="#_1-включение-плагина" aria-label="Permalink to &quot;1. Включение плагина&quot;">​</a></h2><ol><li>Перейдите в <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong>.</li><li>Включите переключатель <strong>Enable Web Adaptive Performance</strong>.</li><li>Разверните вкладку Scalers и включите дополнительные модули (например, Physics Step или Shadows Quality), которые лучше всего подходят под специфику вашей игры (см. подробнее <a href="./../scalers/reference">Scalers Reference</a>).</li></ol><p><img src="'+e+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">По умолчанию</p><p>Настройки по умолчанию уже подобраны для оптимальной работы в большинстве проектов. Вы можете оставить их без изменений.</p></div><h2 id="_2-настроика-player-settings" tabindex="-1">2. Настройка Player Settings <a class="header-anchor" href="#_2-настроика-player-settings" aria-label="Permalink to &quot;2. Настройка Player Settings&quot;">​</a></h2><p>Чтобы ядро плагина (Tracker) могло математически отличать лаги процессора (CPU) от графики (GPU), ему необходим доступ к точным аппаратным таймингам кадра.</p><div class="warning custom-block"><p class="custom-block-title">Frame Timing Stats</p><p>Обязательно перейдите в <strong>Edit -Project Settings -Player -Other Settings -Rendering</strong> и поставьте галочку <strong>Frame Timing Stats</strong>. Без этой настройки определение Bottleneck не будет работать.</p></div><h2 id="_3-настроика-графики" tabindex="-1">3. Настройка графики <a class="header-anchor" href="#_3-настроика-графики" aria-label="Permalink to &quot;3. Настройка графики&quot;">​</a></h2><p>Вам больше не нужно создавать отдельные пресеты качества (Low, Medium, High) под разные устройства и заставлять игрока выбирать их вручную.</p><div class="tip custom-block"><p class="custom-block-title">Ставьте графику на максимум</p><p>Настройте проект на максимальное качество. Для BiRP это делается в <code>Project Settings -Quality</code>, а для URP — внутри вашего <code>URP Asset</code>. Если устройство игрока не справится, плагин сам плавно снизит нагрузку, используя только те скейлеры, которые вы включили.</p></div>',12)])])}const _=a(o,[["render",l]]);export{h as __pageData,_ as default};
